const numbersToWords=z=>{const J=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(z<0x14)return J[z];if(z<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](z/0xa)]+(z%0xa?'\x20'+J[z%0xa]:'');if(z<0x3e8){const Z=Math['floor'](z/0x64),c=z%0x64;return(0x1===Z?'εκατό':0x2===Z?'διακόσια':0x3===Z?'τριακόσια':0x4===Z?'τετρακόσια':0x5===Z?'πεντακόσια':0x6===Z?'εξακόσια':0x7===Z?'επτακόσια':0x8===Z?'οκτακόσια':0x9===Z?'εννιακόσια':'')+(c?'\x20'+numbersToWords(c):'');}return z<0xf4240?numbersToWords(Math['floor'](z/0x3e8))+'\x20χιλιάδες'+(z%0x3e8?'\x20'+numbersToWords(z%0x3e8):''):numbersToWords(Math['floor'](z/0xf4240))+'\x20εκατομμύρια'+(z%0xf4240?'\x20'+numbersToWords(z%0xf4240):'');},numberToText=(z,J='money')=>{const Z=Math['floor'](z),c=Math['round'](0x64*(z-Z));let i=numbersToWords(Z),W=c>0x0?numbersToWords(c):'';switch(J){case'money':return W?i+'\x20ευρώ\x20και\x20'+W+'\x20λεπτά':i+'\x20ευρώ';case'time':return W?i+'\x20ώρες\x20και\x20'+W+'\x20λεπτά':i+'\x20ώρες';default:return W?i+'\x20και\x20'+W:''+i;}};